CREATE TABLE accounts (
  id INT PRIMARY KEY,
  owner VARCHAR(50),
  balance DECIMAL(10,2)
);

INSERT INTO accounts VALUES
  (1, 'Alice', 1000.00),
  (2, 'Bob',   500.00),
  (3, 'Carol', 750.00);

-- ATOMICITY: Transfer $200 from Alice to Bob (both operations must succeed or both fail)
BEGIN;
  UPDATE accounts SET balance = balance - 200 WHERE id = 1;  -- debit Alice
  UPDATE accounts SET balance = balance + 200 WHERE id = 2;  -- credit Bob
COMMIT;

-- CONSISTENCY: Verify total balance unchanged after transfer
SELECT SUM(balance) AS total_balance FROM accounts;

-- DURABILITY: Once committed, data is persisted
SELECT id, owner, balance FROM accounts ORDER BY id;

CREATE TABLE inventory (
  product_id INT PRIMARY KEY,
  product_name VARCHAR(50),
  stock INT,
  reserved INT DEFAULT 0
);

INSERT INTO inventory VALUES
  (1, 'Laptop',   100, 0),
  (2, 'Mouse',    500, 0),
  (3, 'Keyboard', 200, 0);

-- Check state before transaction
SELECT * FROM inventory;

-- Simulated transaction that fails:
BEGIN;
  UPDATE inventory SET stock = stock - 10, reserved = reserved + 10 WHERE product_id = 1;
  UPDATE inventory SET stock = stock - 5,  reserved = reserved + 5  WHERE product_id = 2;
  -- Simulate a failure detected (e.g., validation failed)
  ROLLBACK;  -- undo both updates

-- Check state after rollback — should be same as before
SELECT * FROM inventory;

CREATE TABLE orders (
  id INT PRIMARY KEY,
  customer VARCHAR(50),
  product VARCHAR(50),
  amount DECIMAL(8,2),
  status VARCHAR(20) DEFAULT 'pending'
);

INSERT INTO orders VALUES
  (1, 'Alice', 'Laptop',   999.99, 'completed'),
  (2, 'Bob',   'Mouse',     25.00, 'pending'),
  (3, 'Carol', 'Monitor',  399.00, 'failed'),
  (4, 'Dave',  'Keyboard',  75.00, 'pending'),
  (5, 'Eve',   'Laptop',   999.99, 'completed');

-- Scenario A (Atomicity fix): Update order status AND log it — both in one transaction
BEGIN;
  UPDATE orders SET status = 'completed' WHERE id = 2;
  -- INSERT INTO order_log(order_id, action) VALUES (2, 'completed');  -- would go here
COMMIT;

-- Scenario B (Consistency check): Ensure no negative amounts exist
SELECT id, customer, amount FROM orders WHERE amount <= 0;

-- Scenario C (Query): Count orders by status to monitor the data state
SELECT status, COUNT(*) as count FROM orders GROUP BY status ORDER BY count DESC;
